import { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import API from "../../services/api";
import "./css/UserDashboard.css";

function UserAccount() {
  const [account, setAccount] = useState({});
  const navigate = useNavigate();

  useEffect(() => {
    fetchAccount();
  }, []);

  const fetchAccount = async () => {
    try {
      const res = await API.get("/user/account");
      setAccount(res.data);
    } catch (e) {
      console.error(e);
    }
  };

  const logout = () => {
     navigate("/");
  }

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-logo">
          <div className="logo-icon">⚡</div>
          UserPortal 🚀
        </div>

        <nav className="nav-menu">
          <Link to="/user/dashboard" className="nav-link">🏠 Dashboard</Link>
          <Link to="/user/resume" className="nav-link">📄 My Resume</Link>
          <Link to="/user/alerts" className="nav-link">🔔 Job Alerts</Link>
          <Link to="/user/saved-jobs" className="nav-link">⭐ Saved Jobs</Link>
          <Link to="/user/account" className="nav-link active">⚙️ Account</Link>
        </nav>
      </aside>

      <main className="dashboard-main">
        <header className="dashboard-header-flex">
          <div className="header-titles">
            <h1>Account Settings ⚙️</h1>
            <p>Manage your login details and platform preferences.</p>
          </div>
        </header>

         <div className="update-resume-card" style={{maxWidth: '600px'}}>
             <div style={{marginBottom: '2rem'}}>
               <p style={{color: '#94a3b8', fontSize: '0.875rem', fontWeight: 700, textTransform: 'uppercase'}}>Display Name</p>
               <input className="admin-input" style={{marginTop: '0.5rem', width: '100%', marginBottom: 0}} value={account.name || ""} readOnly />
             </div>

             <div style={{marginBottom: '2rem'}}>
               <p style={{color: '#94a3b8', fontSize: '0.875rem', fontWeight: 700, textTransform: 'uppercase'}}>Email Address</p>
               <input className="admin-input" style={{marginTop: '0.5rem', width: '100%', marginBottom: 0}} value={account.email || ""} readOnly />
             </div>

             <div className="grid-2-cols" style={{marginBottom: '2.5rem'}}>
                <div style={{background: '#f8fafc', padding: '1.5rem', borderRadius: '12px', border: '1px solid #f1f5f9'}}>
                  <p style={{color: '#94a3b8', fontSize: '0.875rem', fontWeight: 700, textTransform: 'uppercase'}}>Status</p>
                  <p style={{fontSize: '1.25rem', fontWeight: 800, color: '#16a34a', marginTop: '0.5rem'}}>{account.status}</p>
                </div>
                <div style={{background: '#f8fafc', padding: '1.5rem', borderRadius: '12px', border: '1px solid #f1f5f9'}}>
                  <p style={{color: '#94a3b8', fontSize: '0.875rem', fontWeight: 700, textTransform: 'uppercase'}}>Member Since</p>
                  <p style={{fontSize: '1.25rem', fontWeight: 800, color: '#1e293b', marginTop: '0.5rem'}}>{account.member_since}</p>
                </div>
             </div>

             <button onClick={logout} style={{background: '#fee2e2', color: '#ef4444', padding: '1rem', width: '100%', border: 'none', borderRadius: '12px', fontWeight: 800, fontSize: '1.125rem', cursor: 'pointer', transition: '0.2s'}}>
                Logout 👋
             </button>
         </div>
      </main>
    </div>
  );
}

export default UserAccount;
